const status = $input.first().json.body || $input.first().json;
const now = Date.now();
const THIRTY_HOURS_MS = 30 * 60 * 60 * 1000;
const FOUR_HUNDRED_DAYS_MS = 400 * 24 * 60 * 60 * 1000;

const alerts = [];

// Check last backup success
if (!status.lastSuccess || !status.lastSuccess.timestamp) {
  alerts.push({ type: 'backup_stale', detail: 'No successful backup on record' });
} else {
  const lastSuccessAge = now - new Date(status.lastSuccess.timestamp).getTime();
  if (lastSuccessAge > THIRTY_HOURS_MS) {
    alerts.push({ type: 'backup_stale', detail: `Last success was ${Math.round(lastSuccessAge/3600000)}h ago` });
  }
}

// Check last verify
if (!status.lastVerify || !status.lastVerify.timestamp) {
  alerts.push({ type: 'verify_stale', detail: 'No successful verify on record' });
} else {
  const lastVerifyAge = now - new Date(status.lastVerify.timestamp).getTime();
  if (lastVerifyAge > THIRTY_HOURS_MS) {
    alerts.push({ type: 'verify_stale', detail: `Last verify was ${Math.round(lastVerifyAge/3600000)}h ago` });
  }
}

// Check disaster drill cadence (finding #5 fix)
// The /status endpoint exposes lastDrill (null if status/last-drill.json is missing)
if (!status.lastDrill || !status.lastDrill.timestamp) {
  alerts.push({ type: 'drill_overdue', detail: 'No disaster drill on record. Perform the annual drill per scripts/backup/README.md §2.5.7 and upload last-drill.json to R2.' });
} else {
  const lastDrillAge = now - new Date(status.lastDrill.timestamp).getTime();
  if (lastDrillAge > FOUR_HUNDRED_DAYS_MS) {
    alerts.push({ type: 'drill_overdue', detail: `Last drill was ${Math.round(lastDrillAge/86400000)} days ago. Annual drill overdue. See scripts/backup/README.md §2.5.7.` });
  }
}

return [{ json: { alerts, status, hasAlerts: alerts.length > 0 } }];
